import { useState, useEffect } from "react";
import { models } from "../data";
import ModelCard from "../components/ModelCard";

export default function Catalog() {
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("All");
  const [visible, setVisible] = useState(true);

  const filtered = models.filter(m =>
    m.name.toLowerCase().includes(search.toLowerCase()) &&
    (filter === "All" || m.type === filter)
  );

  // При смене фильтра — скрыть, потом показать
  const handleFilter = (f) => {
    setVisible(false);
    setTimeout(() => {
      setFilter(f);
      setVisible(true);
    }, 200);
  };

  return (
    <div style={styles.container}>
      <h1>AI Model Index</h1>
      <p style={{ opacity: 0.6 }}>Explore AI models</p>
      <input
        placeholder="Search..."
        value={search}
        onChange={(e) => {
          setVisible(false);
          setTimeout(() => {
            setSearch(e.target.value);
            setVisible(true);
          }, 150);
        }}
        style={styles.input}
      />
      <div style={styles.filters}>
        {["All", "LLM", "Open-source", "Fast"].map(f => (
          <button
            key={f}
            onClick={() => handleFilter(f)}
            style={{
              ...styles.btn,
              background: filter === f ? "#38bdf8" : "#1e293b"
            }}
          >
            {f}
          </button>
        ))}
      </div>

      {/* Анимация через opacity и transform */}
      <div
        style={{
          ...styles.grid,
          opacity: visible ? 1 : 0,
          transform: visible ? "translateY(0)" : "translateY(10px)",
          transition: "opacity 0.2s ease, transform 0.2s ease"
        }}
      >
        {filtered.map(m => <ModelCard key={m.id} model={m} />)}
      </div>

      {filtered.length === 0 && visible && (
        <p style={{ opacity: 0.5, marginTop: "40px", textAlign: "center" }}>
          Ничего не найдено
        </p>
      )}
    </div>
  );
}

const styles = {
  container: {
    padding: "30px",
    background: "#020617",
    minHeight: "100vh",
    color: "#fff",
    fontFamily: "system-ui"
  },
  input: {
    padding: "10px",
    borderRadius: "8px",
    marginTop: "10px",
    width: "250px",
    background: "#1e293b",
    border: "1px solid #334155",
    color: "#fff"
  },
  filters: {
    marginTop: "10px",
    display: "flex",
    gap: "10px"
  },
  btn: {
    padding: "6px 10px",
    border: "none",
    borderRadius: "6px",
    color: "#fff",
    cursor: "pointer",
    transition: "background 0.2s"
  },
  grid: {
    marginTop: "20px",
    display: "grid",
    gap: "15px",
    gridTemplateColumns: "repeat(auto-fill, minmax(250px,1fr))"
  }
};
